export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "正式問話在另一個房間。比站務室小，比站務室冷。牆上沒有窗戶，只有一面不知道是不是單向鏡的玻璃。桌上有一台筆電、一疊空白表格、兩杯紙杯水。日下部坐在她對面。年輕警員坐在旁邊，負責打字。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是審訊室。沒有鐵桌，沒有固定椅，沒有那種電影裡會出現的強光燈。它只是一個普通的、冷的、燈光太白的小房間。但正因為它普通，它才可怕。它讓她覺得自己正在經歷的不是審判，而是填表。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "開始記錄。請從你收到訊息開始說。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我是收到訊息才去的。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說了。和剛才一樣。她收到匿名訊息，訊息告訴她去灣岸新交通第七車，帶上悠真留下的東西。她去了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "年輕警員在筆電上打字。澪看著螢幕上的字一行一行出現。她看見他打的是：", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉澪根據匿名訊息前往指定車廂。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯不是這樣。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說出口。因為她不知道哪裡不對。「我是收到訊息才去的」和「朝倉澪根據匿名訊息前往指定車廂」——字面意思一樣。但讀起來不一樣。她的版本裡有一個「才」字，那個字代表她本來不打算去，是訊息讓她去的。紀錄裡沒有那個字。紀錄裡只有「根據」「前往」「指定」。三個詞。每一個都是對的。組在一起，讀起來像她是有目的地、有計畫地去了那節車廂。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她張嘴想修正。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "然後呢。車上發生了什麼。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "他⋯⋯千田先生把東西交給我。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說「他把東西交給我」。她說的是「交」。是千田主動的。是她被動接過來的。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上的字出來了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉澪承認接觸金屬外殼狀物。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)承認？", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有說「承認」。她說的是「交給我」。但紀錄裡寫的是「承認接觸」。「承認」這個字是她沒有說過的。它被放進去了。像一個人替她翻譯了她的話，翻譯成了一種她不會用的語言。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。它沒有撒謊。她確實接觸了那個東西。她確實承認了。但「承認接觸」和「他把東西交給我」之間有一條縫——那條縫裡裝著千田的手指攥住她的手、把外殼壓進她掌心的那個動作。紀錄裡沒有那條縫。紀錄裡只有她，和她接觸的那個東西。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不是「承認」。是他交給我的。我沒有主動去碰——", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你有接觸嗎？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯有。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "接觸了多久？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我不知道。一直到救護來為止。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她聽見自己的話在房間裡停了一秒。然後她意識到——「一直到救護來」代表她一直握著它。從千田交給她到救護到場，她一直握著一個沾血的、破邊像刀的金屬物。她知道原因。她是在急救，她忘了鬆手。但紀錄不會寫「她忘了鬆手」。紀錄只會寫時間長度。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上又多了一行。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉澪表示接觸時間持續至救護人員到場。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她閉嘴了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你說你在壓他的傷口。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我是在壓他的傷口。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說「壓」。她說「傷口」。她說的是急救。她做的是急救。她的右手壓在千田肋下，掌心貼著血往外滲的那個位置，她在幫他止血。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "螢幕上的字出來了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "朝倉澪雙手及袖口附著千田浩介血液。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著那行字。她的嘴巴張了一下。又合上了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "「雙手及袖口附著千田浩介血液」。這句話是對的。她的雙手確實沾了血。她的袖口確實洇開了一片。但這句話裡沒有「壓」。沒有「傷口」。沒有「急救」。只有「附著」。附著是一個中性的詞。它不說明原因。它只說明狀態。她的雙手附著他的血——這句話可以被讀成「她在急救」，也可以被讀成「她碰過他」。取決於誰在讀。取決於他們想讀成什麼。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有再修正。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是因為她放棄了。是因為她剛剛學到了一件事：每修一次，紀錄就會多一行。每一行都會用她的話造一個新的、更精確的、更沒有溫度的句子。她修得越多，她離自己說過的原話就越遠。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)不是只有畫面會被整理。連我說的話也會。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這個念頭讓她的胃沉了一下。比看見控制中心畫面的時候還沉。畫面至少是別人的東西——是系統拍的、是控制中心壓縮的、是她可以指著說「那不是我」的。但話是她自己說的。從她嘴巴裡出來的。然後被裝進了表格裡。裝進去之後，它就不再是她的了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你提到朝倉悠真的失蹤。你認為這次事件和你弟弟的失蹤有關？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "有關。匿名訊息裡提到悠真。千田也提到——", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "朝倉悠真的失蹤案，目前和本案沒有確認關聯。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他打斷了她。不是凶的那種打斷。是程序性的。像在表格上畫一條分隔線——這一欄和那一欄之間，暫時沒有連線。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "訊息裡寫的是悠真的名字。我會出現在那節車廂，就是因為有人用悠真——", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "也就是說，妳相信一名陌生男子，比相信警方對妳弟弟失蹤案的判斷？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡安靜了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪的手指在桌面上收緊了一下。不是握拳。是那種被什麼東西刺了一下、但來不及喊痛的收緊。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)悠真的失蹤案。警方對悠真失蹤案的判斷。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她知道警方對悠真失蹤案的判斷是什麼。自願離家。十五歲男孩，沒有外傷跡象，沒有脅迫證據，監視器拍到他自己走出住處。自願離家。四個字。案號還掛著，但已經沒有人在查了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "如果她被千田案困住——被列為重大參考人、被限制行動、被反覆傳喚——所有人會更快把悠真失蹤案切回「自願離家」。她越陷越深，悠真就越沒有人管。兩件事會被切開。切開之後，她連把兩件事連起來的資格都沒有了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "悠真的失蹤和千田的案子是同一條線。訊息用悠真的名字把我引去，千田見到我就問我帶了什麼東西——", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "這些是你的推測？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯事情就是按這個順序發生的。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "先後順序不等於因果關係。目前沒有證據顯示朝倉悠真失蹤案與千田浩介傷害案有關聯。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的語氣不凶。他很平。他在做他的工作。他在表格上填欄位。這一欄叫「關聯性」，他填的是「無」。不是因為他討厭她，不是因為他知道什麼，是因為表格上要求證據。她沒有證據。她只有先後順序。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部坐在對面，一直沒有說話。他在看紀錄。他的筆偶爾在資料夾上寫幾個字，但大部分時間他只是看。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著他。他沒有幫她。他也沒有踩她。他只是坐在那裡，像一個被放進房間裡的測量儀器——在記錄什麼，但不輸出任何判斷。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你提到千田浩介說了一句話。「不要救東京」。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯對。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "「東京」指的是什麼？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不知道。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "千田是否提到災害？地震、海嘯、攻擊？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。他只說了那四個字。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你是否認識任何政治團體？或與任何社會運動有關？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不認識。我是大學生。我在網路媒體兼職做資料查核。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Angry },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "朝倉悠真失蹤與這句話有什麼關係？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不知道。我還在查。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "所以你沒有辦法說明這句話的意思。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是問句。是結論。他在紀錄上打了一行字。澪沒有去看。她知道那行字寫的是什麼——「意味不明」「疑似危險語句」「待進一步確認」。她說不出這四個字的意思。她說不出來，紀錄就會把它留成一個空洞。空洞會被填上什麼，不取決於她。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部的筆停了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "半秒。和剛才一樣。他的筆尖懸在紙面上方，視線從紀錄紙移到澪的臉上，停了不到一秒，又移回去。筆落下。繼續寫。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有解釋。他沒有追問。他沒有幫她說明「不要救東京」是什麼意思。他只是停了半秒。像一個人在一條路上走，突然踩到了什麼，低頭看了一眼，確認不是地雷，繼續走。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但那半秒被澪看見了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)他知道些什麼。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她不確定。她不確定那半秒代表什麼。也許他只是想到了別的事。也許他只是手酸了。但她就是覺得——那四個字對他來說不是「意味不明」。對他來說，那四個字是別的什麼。一個他還不能說的什麼。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有問。她知道他不會回答。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "時間在走。她不知道幾點了。房間裡沒有鐘。她的手機不在手邊——還在年輕警員那邊，螢幕朝下放在桌上。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後門響了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是推開。是敲。三下。很輕。像怕打擾到什麼。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "年輕警員起身去開門。門開了一條縫。一隻手從縫裡伸進來，拿著一張紙。警員接過紙，門又關上了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他看那張紙。看了五秒。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他低頭，湊近日下部。聲音很輕。但房間太小了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "醫院那邊確認了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "四個字。澪沒有聽到完整的內容。她不需要聽到。她看見了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見年輕警員說完那句話之後，日下部的肩膀動了一下。不是放鬆，不是緊繃。是那種聽到了一個已經預期但仍然沉重的東西時，肩膀會做的微調。像在重新分配重量。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看見年輕警員回到筆電前面，在紀錄上打了一行字。她看不見全部，但她看見了最前面兩個字。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "死亡確認。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "(內心)⋯⋯死了。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她已經知道了。從月台上救護人員說「心肺停止」的那一刻起，她就知道可能性。但「心肺停止」和「死亡確認」不一樣。「心肺停止」是進行式。「死亡確認」是完成式。完成式沒有回頭路。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "房間裡的空氣變了。不是變冷——已經夠冷了。是變重。像有人把氣壓調高了一格。每個人的呼吸都往下沉了一點。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "年輕警員的坐姿變了。他本來是往後靠的，現在往前傾了。他的手指在鍵盤上的速度變快了。他的問題開始變密。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你再次確認。你與千田浩介之前是否認識？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不認識。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你從未見過他？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯從未見過。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你進入第七車時，車內只有你和千田浩介？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "對。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "從你進入到救護到場，期間沒有其他人進出？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯沒有。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你手中的金屬物是千田浩介交給你的。你沒有從其他地方取得？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "沒有。是他給我的。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你壓住他的傷口時，有沒有看到傷口的形狀？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯沒有。我只看到血。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "你不知道傷口是什麼造成的？", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "不知道。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "問題越來越密。但語氣沒有升高。沒有人拍桌子，沒有人吼她，沒有人說「妳在說謊」。他們只是在問。一個接一個。像在填一張越來越長的表格。每一格都是她。每一格填進去的東西都會變成紀錄的一部分。紀錄會變成檔案。檔案會變成這件事的官方版本。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有被逮捕。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她注意到這一點。死亡確認已經來了，但沒有人說「你被逮捕了」。沒有人念權利。沒有人拿出手銬。她不知道為什麼。也許是因為死因還沒鑑定。也許是因為外殼是不是凶器還沒鑑定。也許是因為她的手上有血但她的衣服裡面是乾淨的。也許是因為控制中心的畫面有時間碼問題。她不知道。她只知道她還坐在這把椅子上，門還沒有被鎖上。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她不覺得這是自由。她覺得這是暫停。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "手機的部分。初步取證已完成。匿名訊息已拍照記錄。對話紀錄已初步備份。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他把她的手機從桌上拿起來，翻過來，螢幕朝上，遞給她。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.PoliceOfficer, character: "警員", dialogue: "不要刪除任何資料。明天還要配合完整取證。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪接過手機。螢幕亮了一下。她看見訊息列表。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有刻意去看。她的眼睛只是掃過去了。像經過一面櫥窗，不自覺地看了一眼裡面的東西。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "白石琴音　已讀 21:19。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一行字。在訊息列表的中間。琴音的名字。後面跟著「已讀 21:19」。她發給琴音的訊息，琴音看了。二十一點十九分。在她上車之前兩分鐘。琴音看了，沒有回。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有深究。她沒有時間深究。她的大腦已經被問題塞滿了——千田、外殼、血、畫面、悠真、東京。琴音的已讀未回只是列表裡的一行字，一閃而過，像路燈從車窗外掠過的那種一閃。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但她記住了。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "妳現在刪掉任何東西，都會變成另一個問題。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "日下部的聲音。冷的。不是威脅的冷，是陳述的冷。像在念一條規則。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯我知道。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機收進斜背包外側的口袋。拉鏈拉上。她的手指在拉鏈上停了一秒——背包裡面，最內層的小布套裡，那個圓的、薄的、硬的東西還在。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個問題還會回來。只是現在還沒輪到它。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她能感覺到。像一顆還沒被翻開的牌。它還壓在牌堆下面。但它的重量一直在那裡。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.KusakubeSatoru, character: "日下部", dialogue: "回答妳確定的事。不要替死者解釋。", background: Background.Chapter_3_Ch3_Act5_S0, portrait: Portrait.KusakubeSatoru_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他又說了一遍。和剛才在站務室裡說的一樣。同一句話。同一個語氣。像一把尺——量她的話，也量她的沉默。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "澪看著他。他的臉在燈光下沒有表情。眼睛很暗。她讀不出他在想什麼。她不知道這句話是在保護她，還是在限制她。「回答妳確定的事」——這句話可以讀成「不要亂說話，免得被扭曲」，也可以讀成「不要說太多，免得暴露自己」。她不知道是哪一個。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "也許兩個都是。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她低下頭。看著桌面。桌面是金屬的，冷光的，映出她自己的輪廓——模糊的，像水面上的一層油。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她說過的每一句話，都被裝進了表格。表格裡的她，根據匿名訊息前往指定車廂，承認接觸金屬外殼狀物，雙手及袖口附著千田浩介血液。那個人沒有壓過傷口。那個人沒有被塞過東西。那個人只是一個出現在死亡現場的、手上有血的、和死者單獨待在一節車廂裡的女人。", background: Background.Chapter_3_Ch3_Act5_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是只有影像會被整理。連她說出的話，也會被整理成另一個故事。", background: Background.Chapter_3_Ch3_Act5_S0 },
];
